package com.example

import org.junit.Assert.*
import org.junit.Test
import java.io.File
import java.util.Base64

class ExampleUnitTest {
  @Test
  fun addition_isCorrect() {
    assertEquals(4, 2 + 2)
  }

  @Test
  fun decodeImage() {
    val b64 = ""
    var rawB64 = b64.filter { it in 'A'..'Z' || it in 'a'..'z' || it in '0'..'9' || it == '+' || it == '/' }
    if (rawB64.length % 4 == 1) {
      rawB64 = rawB64.substring(0, rawB64.length - 1)
    }
    val paddedLength = ((rawB64.length + 3) / 4) * 4
    val sanitizedB64 = rawB64.padEnd(paddedLength, '=')
    val bytes = try {
      Base64.getDecoder().decode(sanitizedB64)
    } catch (e: Exception) {
      throw IllegalArgumentException("Len: ${b64.length}, rawLen: ${rawB64.length}, sanitizedLen: ${sanitizedB64.length}, error: ${e.message}, prefix: ${b64.take(30)}, suffix: ${b64.takeLast(30)}")
    }
    val dir = File("app/src/main/res/drawable")
    if (!dir.exists()) {
      dir.mkdirs()
    }
    val file = File(dir, "tg_logo.png")
    file.writeBytes(bytes)
    assertTrue(file.exists() && file.length() > 0)
  }
}

